"""
Recursive-descent expression evaluator.

Grammar (lowest → highest precedence):
    expr   ::= term   (('+' | '-') term)*
    term   ::= factor (('*' | '/') factor)*
    factor ::= NUMBER | '(' expr ')'
"""


class Parser:
    def __init__(self, text: str):
        self.tokens = tokenize(text)
        self.pos = 0

    # --- token helpers ---

    def peek(self):
        """Return the current token without consuming it, or None at end."""
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self):
        """Return and advance past the current token."""
        tok = self.tokens[self.pos]
        self.pos += 1
        return tok

    def expect(self, value):
        """Consume and assert the next token equals *value*."""
        tok = self.consume()
        if tok != value:
            raise ValueError(f"Expected {value!r}, got {tok!r}")
        return tok

    # --- grammar rules ---

    def parse_expr(self) -> float:
        """expr ::= term (('+' | '-') term)*"""
        result = self.parse_term()
        while self.peek() in ('+', '-'):
            op = self.consume()
            right = self.parse_term()
            if op == '+':
                result += right
            else:
                result -= right
        return result

    def parse_term(self) -> float:
        """term ::= factor (('*' | '/') factor)*"""
        result = self.parse_factor()
        while self.peek() in ('*', '/'):
            op = self.consume()
            right = self.parse_factor()
            if op == '*':
                result *= right
            else:
                result /= right
        return result

    def parse_factor(self) -> float:
        """factor ::= NUMBER | '(' expr ')'"""
        tok = self.peek()
        if tok == '(':
            self.consume()          # eat '('
            result = self.parse_expr()
            self.expect(')')
            return result
        # must be a number
        self.consume()
        return float(tok)


def tokenize(text: str) -> list[str]:
    """Split expression into a flat list of number strings and operator/paren chars."""
    tokens = []
    i = 0
    while i < len(text):
        ch = text[i]
        if ch.isspace():
            i += 1
        elif ch in '+-*/()':
            tokens.append(ch)
            i += 1
        elif ch.isdigit() or ch == '.':
            j = i
            while j < len(text) and (text[j].isdigit() or text[j] == '.'):
                j += 1
            tokens.append(text[i:j])
            i = j
        else:
            raise ValueError(f"Unexpected character: {ch!r}")
    return tokens


def evaluate(expression: str) -> float:
    """Parse and evaluate an arithmetic expression string."""
    parser = Parser(expression)
    result = parser.parse_expr()
    if parser.peek() is not None:
        raise ValueError(f"Unexpected token: {parser.peek()!r}")
    return result

